+/** Retry a task-producing function immediately up to `n` additional times after rejection. */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  return new Task((resolve, reject) => {
+    let remaining = Math.max(0, Math.floor(n));
+    const attempt = () => {
+      let task: Task<T, E>;
+      try {
+        task = fn();
+      } catch (error) {
+        reject(error as E);
+        return;
+      }
+      task.match({
+        Resolved: resolve,
+        Rejected: (reason) => {
+          if (remaining-- > 0) attempt();
+          else reject(reason);
+        },
+      });
+    };
+    attempt();
+  });
